%[text] Step 1 - Self-Ordered Maps (SOM) Training
function som = som_train(train_data, train_labels, class_names, map_rows, map_cols, num_epochs)
% SOM_TRAIN  Trains a Self-Organising Map classifier
%
% Improvements over previous version:
%   - Weights initialised by sampling from training data (faster convergence)
%   - Faster neighbourhood decay for tighter class specialisation
%   - Clearer epoch progress reporting

num_neurons = map_rows * map_cols;
feature_dim = size(train_data, 2);
num_samples = size(train_data, 1);
num_classes = length(class_names);

% ----------------------------------------------------------
% Initialise weights by sampling random training vectors
% Faster convergence than pure random initialisation
% ----------------------------------------------------------
rand_idx = randperm(num_samples, num_neurons);
weights  = train_data(rand_idx, :);

fprintf('SOM: %dx%d grid (%d neurons) | feature dim=%d | epochs=%d\n', ...
    map_rows, map_cols, num_neurons, feature_dim, num_epochs);

% ----------------------------------------------------------
% Precompute neuron grid positions
% ----------------------------------------------------------
neuron_rows = zeros(num_neurons, 1);
neuron_cols = zeros(num_neurons, 1);
for k = 1:num_neurons
    neuron_rows(k) = floor((k-1) / map_cols) + 1;
    neuron_cols(k) = mod((k-1),   map_cols)  + 1;
end

% ----------------------------------------------------------
% Hyperparameters
% sigma decays more aggressively — tighter neighbourhood
% means neurons specialise more to individual classes
% ----------------------------------------------------------
alpha_0 = 0.5;
sigma_0 = max(map_rows, map_cols) / 2;
sigma_f = 0.5;   % final neighbourhood radius

% ----------------------------------------------------------
% Training loop
% ----------------------------------------------------------
for epoch = 1:num_epochs

    % Exponential decay for smoother convergence
    t      = epoch / num_epochs;
    alpha  = alpha_0 * exp(-3 * t);
    sigma  = sigma_0 * exp(-3 * t) + sigma_f;

    % Shuffle training order each epoch
    order = randperm(num_samples);

    for s = 1:num_samples

        x = train_data(order(s), :);

        % --- Find BMU ---
        min_dist = inf;
        bmu      = 1;
        for k = 1:num_neurons
            d = sum((x - weights(k,:)).^2);
            if d < min_dist
                min_dist = d;
                bmu      = k;
            end
        end

        % --- Update weights ---
        bmu_r = neuron_rows(bmu);
        bmu_c = neuron_cols(bmu);

        for k = 1:num_neurons
            grid_dist_sq = (neuron_rows(k) - bmu_r)^2 + ...
                           (neuron_cols(k) - bmu_c)^2;
            influence = exp(-grid_dist_sq / (2 * sigma^2));
            weights(k,:) = weights(k,:) + ...
                alpha * influence * (x - weights(k,:));
        end

    end

    if mod(epoch, 10) == 0 || epoch == 1
        fprintf('  Epoch %3d/%d | alpha=%.4f | sigma=%.4f\n', ...
            epoch, num_epochs, alpha, sigma);
    end

end

% ----------------------------------------------------------
% Label neurons by majority vote over training set
% ----------------------------------------------------------
neuron_class_counts = zeros(num_neurons, num_classes);

for s = 1:num_samples
    x        = train_data(s, :);
    min_dist = inf;
    bmu      = 1;
    for k = 1:num_neurons
        d = sum((x - weights(k,:)).^2);
        if d < min_dist
            min_dist = d;
            bmu      = k;
        end
    end
    neuron_class_counts(bmu, train_labels(s)) = ...
        neuron_class_counts(bmu, train_labels(s)) + 1;
end

neuron_labels = zeros(num_neurons, 1);
for k = 1:num_neurons
    if sum(neuron_class_counts(k,:)) > 0
        [~, neuron_labels(k)] = max(neuron_class_counts(k,:));
    end
end

unlabeled = sum(neuron_labels == 0);
fprintf('Neuron labeling complete. Unlabeled neurons: %d/%d\n', ...
    unlabeled, num_neurons);

% ----------------------------------------------------------
% Pack SOM struct
% ----------------------------------------------------------
som.weights       = weights;
som.neuron_labels = neuron_labels;
som.class_names   = class_names;
som.map_rows      = map_rows;
som.map_cols      = map_cols;
som.feature_dim   = feature_dim;
som.num_classes   = num_classes;

end
%[text] Step 2 - SOM Classification Function
function [predicted_label, predicted_name] = som_classify(som, x)
% SOM_CLASSIFY  Classifies a feature vector using a trained SOM
%               Skips unlabeled neurons (label=0) when finding BMU

num_neurons = size(som.weights, 1);
min_dist    = inf;
bmu         = 1;

for k = 1:num_neurons
    d = sum((x - som.weights(k,:)).^2);
    if d < min_dist
        min_dist = d;
        bmu      = k;
    end
end

% If BMU is unlabeled, search for nearest labeled neuron
if som.neuron_labels(bmu) == 0
    min_dist_labeled = inf;
    for k = 1:num_neurons
        if som.neuron_labels(k) > 0
            d = sum((x - som.weights(k,:)).^2);
            if d < min_dist_labeled
                min_dist_labeled = d;
                bmu              = k;
            end
        end
    end
end

predicted_label = som.neuron_labels(bmu);
predicted_name  = som.class_names{predicted_label};

end
%[text] Step 3 - Dataset Loading Function
function [train_data, train_labels, val_data, val_labels] = load_som_dataset(dataset_path, class_folders, class_labels, train_ratio)
% LOAD_SOM_DATASET  Loads .mat samples and splits into train/validation sets
%
% Usage:
%   [train_data, train_labels, val_data, val_labels] = ...
%       load_som_dataset(dataset_path, class_folders, class_labels, train_ratio)
%
% Inputs:
%   dataset_path  — path to dataset root folder e.g. 'p_dataset_26'
%   class_folders — cell array of subfolder names
%   class_labels  — integer label for each folder
%   train_ratio   — fraction of data used for training e.g. 0.75
%
% Outputs:
%   train_data    — [n_train x 676] normalised training feature matrix
%   train_labels  — [n_train x 1]   training class labels
%   val_data      — [n_val x 676]   normalised validation feature matrix
%   val_labels    — [n_val x 1]     validation class labels

train_data   = [];
train_labels = [];
val_data     = [];
val_labels   = [];

for c = 1:length(class_folders)

    folder_path = fullfile(dataset_path, class_folders{c});
    files       = dir(fullfile(folder_path, '*.mat'));
    num_files   = length(files);

    % Shuffle files for this class before splitting
    shuffle_idx = randperm(num_files);
    files       = files(shuffle_idx);

    % Compute split index
    num_train = floor(num_files * train_ratio);

    class_data = zeros(num_files, 676);

    % Load all samples for this class
    for f = 1:num_files
        file_path          = fullfile(folder_path, files(f).name);
        data               = load(file_path);
        img                = double(data.imageArray) / 255;
        class_data(f, :)   = reshape(img, 1, []);
    end

    % Split into train and validation
    train_data   = [train_data;   class_data(1:num_train, :)];
    train_labels = [train_labels; repmat(class_labels(c), num_train, 1)];

    val_data     = [val_data;     class_data(num_train+1:end, :)];
    val_labels   = [val_labels;   repmat(class_labels(c), num_files-num_train, 1)];

    fprintf('Class %d (%s): %d train | %d validation\n', ...
        class_labels(c), class_folders{c}, num_train, num_files-num_train);

end

fprintf('Total — Train: %d | Validation: %d | Feature dim: %d\n', ...
    size(train_data,1), size(val_data,1), size(train_data,2));

end
%[text] Step 4 - Character Resize Function
function resized = resize_nearest(img, target_rows, target_cols)
% RESIZE_NEAREST  Resizes a binary/grayscale image using nearest neighbor
%
% Resizes img to target_rows x target_cols using backward mapping
% and nearest neighbor interpolation — no toolbox required
%
% Usage:
%   resized = resize_nearest(img, target_rows, target_cols)

[src_rows, src_cols] = size(img);
resized = zeros(target_rows, target_cols, 'double');

for r = 1:target_rows
    for c = 1:target_cols
        % Map output pixel back to input coordinates
        r_src = round(r * src_rows / target_rows);
        c_src = round(c * src_cols / target_cols);

        % Clamp to valid range
        r_src = max(1, min(r_src, src_rows));
        c_src = max(1, min(c_src, src_cols));

        resized(r, c) = img(r_src, c_src);
    end
end

end
%[text] Step 5 - Validate Accuracy
function accuracy = som_validate(som, val_data, val_labels, class_names)
% SOM_VALIDATE  Evaluates trained SOM on validation set
%
% Reports per-class accuracy and overall accuracy
%
% Usage:
%   accuracy = som_validate(som, val_data, val_labels, class_names)

num_val     = size(val_data, 1);
num_classes = length(class_names);
correct     = 0;

% Per-class tracking
class_correct = zeros(1, num_classes);
class_total   = zeros(1, num_classes);

for s = 1:num_val
    [pred_label, ~] = som_classify(som, val_data(s,:));
    true_label      = val_labels(s);

    class_total(true_label) = class_total(true_label) + 1;

    if pred_label == true_label
        correct                   = correct + 1;
        class_correct(true_label) = class_correct(true_label) + 1;
    end
end

accuracy = correct / num_val * 100;

% ----------------------------------------------------------
% Report results
% ----------------------------------------------------------
fprintf('\n===== Validation Results =====\n');
fprintf('%-12s | %-8s | %-8s | %-10s\n', 'Class', 'Correct', 'Total', 'Accuracy');
fprintf('%s\n', repmat('-', 1, 46));
for c = 1:num_classes
    class_acc = class_correct(c) / class_total(c) * 100;
    fprintf('%-12s | %-8d | %-8d | %6.2f%%\n', ...
        class_names{c}, class_correct(c), class_total(c), class_acc);
end
fprintf('%s\n', repmat('-', 1, 46));
fprintf('%-12s | %-8d | %-8d | %6.2f%%\n', ...
    'OVERALL', correct, num_val, accuracy);
fprintf('==============================\n\n');

end
%[text] Step 6 - Main Script
% ==========================================================
% Main Pipeline — SOM Character Classification
% Train/Validation split: 75% train, 25% validation
% ==========================================================

% ----------------------------------------------------------
% 1. Load and display original image
% ----------------------------------------------------------
%coded_array = load_coded_image('data\charact1.txt');
figure(1)
subplot(1,2,1) %[output:6511d0b9]
imshow(coded_array, DisplayRange=[1 32]) %[output:6511d0b9]
title('Original Image') %[output:6511d0b9]

% ----------------------------------------------------------
% 2. Binarize using Otsu's method
% ----------------------------------------------------------
%[T, threshold] = otsu_threshold(coded_array);
subplot(1,2,2) %[output:6511d0b9]
imshow(T) %[output:6511d0b9]
title(sprintf('Binarized — Otsu threshold = %d', threshold)) %[output:6511d0b9]

% ----------------------------------------------------------
% 3. Segment characters using CCL
% ----------------------------------------------------------
%[label_matrix, num_components] = ccl_two_pass(T, 0);
fprintf('Characters detected: %d\n', num_components); %[output:13ae7ced]

% ----------------------------------------------------------
% 4. Load dataset with 75/25 train/validation split
% ----------------------------------------------------------
dataset_path  = 'data\p_dataset_26';
class_folders = {'Sample1','Sample2','Sample3','SampleA','SampleB','SampleC'};
class_names   = {'1','2','3','A','B','C'};
class_labels  = [1, 2, 3, 4, 5, 6];
train_ratio   = 0.75;

[train_data, train_labels, val_data, val_labels] = ... %[output:group:28c648ce] %[output:30a1fecc]
    load_som_dataset(dataset_path, class_folders, class_labels, train_ratio); %[output:group:28c648ce] %[output:30a1fecc]

% ----------------------------------------------------------
% 5. Train SOM — 10x10 grid, 100 epochs
% ----------------------------------------------------------
map_rows   = 10;
map_cols   = 10;
num_epochs = 100;

fprintf('\nTraining SOM (%dx%d grid, %d epochs)...\n', ... %[output:group:10cd9665] %[output:106bd54b]
    map_rows, map_cols, num_epochs); %[output:group:10cd9665] %[output:106bd54b]
som = som_train(train_data, train_labels, class_names, ... %[output:group:22a229d3] %[output:96a1154d]
                map_rows, map_cols, num_epochs); %[output:group:22a229d3] %[output:96a1154d]

% ----------------------------------------------------------
% 6. Validate on held-out 25% — report accuracy per class
% ----------------------------------------------------------
val_accuracy = som_validate(som, val_data, val_labels, class_names); %[output:3e63f4b0]

% ----------------------------------------------------------
% 7. Extract each character, classify, display results
% ----------------------------------------------------------
[rows_img, cols_img] = size(label_matrix);

figure(2)
sgtitle(sprintf('SOM Classification Results  |  Validation Accuracy: %.1f%%', ... %[output:group:02bc6872] %[output:6511d0b9]
    val_accuracy)) %[output:group:02bc6872] %[output:6511d0b9]

for k = 1:num_components %[output:group:706462d0]

    % --- Bounding box extraction ---
    r_min = rows_img; r_max = 1;
    c_min = cols_img; c_max = 1;

    for r = 1:rows_img
        for c = 1:cols_img
            if label_matrix(r, c) == k
                if r < r_min, r_min = r; end
                if r > r_max, r_max = r; end
                if c < c_min, c_min = c; end
                if c > c_max, c_max = c; end
            end
        end
    end

    % --- Padding ---
    pad   = 2;
    r_min = max(r_min - pad, 1);
    r_max = min(r_max + pad, rows_img);
    c_min = max(c_min - pad, 1);
    c_max = min(c_max + pad, cols_img);

    % --- Crop and resize to 26x26 ---
    char_crop    = T(r_min:r_max, c_min:c_max);
    char_resized = resize_nearest(char_crop, 26, 26);

    % --- Normalise: training data has 0=black, 255=white scaled to 0..1
    %     Binary image has 0=black, 1=white — already in [0,1] range
    %     No additional normalisation needed
    feature_vec = reshape(double(char_resized), 1, []);

    % --- Classify ---
    [pred_label, pred_name] = som_classify(som, feature_vec);

    % --- Display subplot ---
    subplot(1, num_components, k) %[output:3d1fa78f]
    imshow(char_crop)
    title(sprintf('Component %d\nPredicted: "%s"', k, pred_name), ...
        'FontSize', 10)

end %[output:group:706462d0]

fprintf('Classification of image characters complete.\n'); %[output:0704dd17]

